"""
MKT Christ Commentary — Psalms chapters 120–133 (Psalms of Ascent)
Run: python3 scripts/zc-christ-psalms-120-133.py

Source data used:
- data/interlinear/psalms.json
- data/commentary/mkt-christ/psalms.json (continuity)

Key Christological decisions in this range:
- Psalms of Ascent (120–134) are pilgrimage songs sung on the way to Jerusalem.
  The Christological thread: the pilgrimage to the earthly city → pilgrimage to the
  heavenly Jerusalem through Christ (Heb 12:22); the Lord who guards and keeps Israel
  → Christ as the sleepless intercessor (Heb 7:25); the peace of Jerusalem → Christ
  himself is our peace (Eph 2:14).
- Ps 130: The De Profundis — "out of the depths I cry" — type of Christ's descent into
  death and cry from the cross (Matt 27:46 / Eph 4:9); v.8 "he will redeem Israel from
  all his iniquities" is directly fulfilled in Matt 1:21 (angel's announcement to Joseph).
- Ps 132: The Davidic covenant — most explicitly messianic psalm in this group. v.11
  "one of the sons of your body I will set on your throne" is directly quoted by Peter
  in Acts 2:30; v.17 "I have prepared a lamp for my anointed" is in Luke 1:69 (Benedictus).
- Ps 133: "How good and pleasant when brothers dwell in unity" → Christ's high-priestly
  prayer (John 17:21-23); v.2 oil on Aaron = Spirit poured out from Christ at Pentecost
  (Acts 2:33).
- Ps 121: "neither slumber nor sleep" → Heb 7:25 (always lives to intercede).
- Ps 124:8 "our help is in the name of the LORD" → Acts 4:12 (no other name for salvation).
- Ps 126:5-6 sow in tears / reap with joy → John 12:24 (grain of wheat).
- Ps 127:1 "unless the LORD builds the house" → Matt 16:18 (I will build my church).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PSALMS = {
  "120": {
    "1": '<p>A type: the righteous sufferer crying to God while hemmed in by hostile forces. The pattern reaches its apex in Christ — Gethsemane (<em>"My soul is very sorrowful, even to death"</em>, Mark 14:34) and the cross (Matt 27:46 = Ps 22:1). The cry that God hears in distress is the same cry Christ made as the embodiment of Israel in extremity, and God answered it through the resurrection.</p>',
    "2": '<p>A theme: deliverance from the deceitful tongue. Christ stood surrounded by false witnesses at his trial (Matt 26:59-60; Mark 14:55-56), fulfilling the pattern of the innocent one falsely accused. He is the Truth (John 14:6) opposed by the father of lies (John 8:44); his vindication by the resurrection is the definitive answer to the lying lips that sought his death.</p>',
    "3": '<p>A revelation of God: the God of <strong>just recompense</strong> whose punishment matches the crime. Christ will execute this final justice at his return — 2 Thess 2:8 ("slain by the breath of his mouth"); Rev 19:11-15. The God who hates the lying tongue is the God who entrusted all judgment to the Son (John 5:22).</p>',
    "4": '<p>A revelation of God: <strong>warrior arrows</strong> and burning coals as instruments of divine judgment on the deceiver. This belongs to the eschatological justice Christ will execute — the same Christ who warned that every careless word will be judged (Matt 12:36) and who is described in Rev 19:15 as striking the nations with a sharp sword from his mouth.</p>',
    "5": '<p>A theme: the exile condition — dwelling among those hostile to God. Christ was himself an alien in a world that rejected him: John 1:11 ("he came to his own, and his own people did not receive him"). The pilgrim psalm sung toward Jerusalem is the prayer of one who longs for the true homeland, which Heb 11:16 identifies as the heavenly country that God has prepared.</p>',
    "6": '<p>A theme: "too long have I had my dwelling among those who hate peace." Christ dwelt his entire ministry among those who would ultimately reject and crucify him. Luke 19:42 — he wept over Jerusalem because it "did not know the things that make for peace." His presence was the peace they refused.</p>',
    "7": '<p>A direct: <strong>"I am for peace, but when I speak, they are for war."</strong> The Prince of Peace (Isa 9:6) came preaching peace (Luke 19:38; Eph 2:17 — "he came and preached peace to you who were far off") and was met with hostility. Eph 2:14 — "he himself is our peace, who has made the two groups one." The verse prefigures the reception of the Messiah whose peace proclamation was answered with crucifixion.</p>',
  },
  "121": {
    "1": '<p>A revelation of God: the question "from where does my help come?" is the question the psalm immediately answers — from YHWH the creator. In the NT, the creator-helper has entered his creation: John 1:3,14 — "all things were made through him... the Word became flesh." Christ is the help that comes "from the LORD" in the most literal sense — the divine helper incarnate.</p>',
    "2": '<p>A revelation of God: <strong>"My help comes from the LORD, who made heaven and earth."</strong> Col 1:16-17 identifies Christ as the one through whom all things in heaven and earth were created and in whom all things hold together. The maker of heaven and earth who is the help of Israel is the Christ through whom that creation was made. Heb 2:18 — because he himself suffered, "he is able to help those who are being tempted."</p>',
    "3": '<p>A shadow: the keeper who prevents the foot from slipping. John 10:28-29 — "I give them eternal life, and they shall never perish; no one will snatch them out of my hand." Christ is the keeper who holds his people so securely that their feet cannot ultimately be moved. 1 Pet 1:5 — believers "are guarded through faith for a salvation ready to be revealed."</p>',
    "4": '<p>A shadow: <strong>"He who keeps Israel will neither slumber nor sleep."</strong> The sleepless guardian finds its NT fulfillment in Christ, the permanent intercessor. Heb 7:25 — "he always lives to make intercession for them." Never off duty, never asleep — Christ prays for his people continuously and permanently from his place at the Father\'s right hand (Rom 8:34).</p>',
    "5": '<p>A theme: "the LORD is your shade on your right hand." The imagery of protective shade points toward Christ as the one in whom believers find shelter. John 10:9 — "I am the door; whoever enters by me will be saved and will go in and out and find pasture." Matt 23:37 — Christ longed to gather Jerusalem "as a hen gathers her chicks under her wings" — the shade and cover of his own person.</p>',
    "6": '<p>A theme: protection from the elements — sun and moon. The total, comprehensive protection described is the protection believers have in Christ. Rom 8:38-39 — nothing in all creation shall separate us from the love of God in Christ Jesus. Rev 7:16 — those before the throne "shall hunger no more, neither thirst anymore; the sun shall not strike them, nor any scorching heat."</p>',
    "7": '<p>A shadow: "He will keep your going out and your coming in." The Good Shepherd who "goes before" his sheep (John 10:3-4), who calls them by name and leads them — Christ is the guardian of every movement of his people. 1 Pet 2:25 — "you were straying like sheep, but have now returned to the Shepherd and Overseer of your souls." The keeping is eternal: "from this time forth and forevermore."</p>',
    "8": '<p>A shadow: <strong>everlasting keeping — "from this time forth and forevermore."</strong> John 11:25-26 — "I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live, and everyone who lives and believes in me shall never die." The eternal dimension of the keeper\'s protection is realized in Christ\'s resurrection — the keeper who conquered death keeps his own for eternity.</p>',
  },
  "122": {
    "1": '<p>A theme: the joy of pilgrimage to God\'s house is fulfilled and surpassed in the approach to God through Christ. Heb 12:22 — "you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem." Eph 2:18 — "through him we both have access in one Spirit to the Father." The gladness of going to the LORD\'s house is now the gladness of those who come to God through Christ.</p>',
    "2": '<p>A theme: standing within Jerusalem\'s gates. John 10:9 — "I am the gate; whoever enters through me will be saved." The gates of the earthly Jerusalem give way to the gates of the heavenly city that are never shut (Rev 21:25). The pilgrim who stood within Jerusalem\'s gates now approaches the new Jerusalem through Christ, the only gate.</p>',
    "3": '<p>A theme: the city "bound firmly together" — the unity of the gathered people. John 11:52 — Christ died "to gather into one the children of God who are scattered abroad." The firmly bound city is a picture of the church that Christ builds (Matt 16:18) — a community held together not by geography but by union with him.</p>',
    "4": '<p>A theme: "to give thanks to the name of the LORD." The name before which all nations bow is the name of Jesus — Phil 2:10-11 ("at the name of Jesus every knee should bow... and every tongue confess that Jesus Christ is Lord"). The universal thanksgiving the psalm envisions is the thanksgiving that flows from every nation through Christ.</p>',
    "5": '<p>A shadow: <strong>"Thrones for judgment were set, the thrones of the house of David."</strong> The Davidic judgment throne is fulfilled in Christ the king-judge. Acts 2:30 — God swore to set "one of his descendants on his throne"; Rev 3:7 — Christ holds "the key of David." He is both the ruler on David\'s throne and the appointed judge of all (Acts 17:31).</p>',
    "6": '<p>A theme: "pray for the peace of Jerusalem." Christ wept over Jerusalem because it did not recognize "the things that make for peace" in its time of visitation (Luke 19:41-44). He is the answer to the prayer — Eph 2:14 "he himself is our peace," the one who reconciles both Jew and Gentile to God and to each other.</p>',
    "7": '<p>A theme: "peace be within your walls and security within your towers." The security that eludes earthly Jerusalem is the security of the heavenly city. Heb 11:10 — Abraham "was looking forward to the city that has foundations, whose designer and builder is God." The walls that never fall are the walls of the new Jerusalem (Rev 21:12-19).</p>',
    "8": '<p>A direct: <strong>"Peace be within you!"</strong> — Christ\'s first words to his gathered disciples after the resurrection. John 20:19,21,26 — "Peace be with you." The peace that the pilgrim prays for Jerusalem\'s sake, Christ pronounces over his gathered community. The resurrection greeting is the definitive answer to the pilgrimage prayer.</p>',
    "9": '<p>A type: "for the sake of the house of the LORD our God, I will seek your good." Zeal for God\'s house drove Christ to cleanse the temple — John 2:17 ("Zeal for your house will consume me" = Ps 69:9). His zeal climaxed in the cross, where he gave himself as the final offering, making himself both the temple and the sacrifice (John 2:19-21).</p>',
  },
  "123": {
    "1": '<p>A shadow: "To you I lift up my eyes, O you who are enthroned in the heavens." The one enthroned in heaven is now identified as Christ, the ascended Lord — Heb 1:3 ("sat down at the right hand of the Majesty on high"); Rev 1:12-18 (the risen Christ enthroned in glory). Eyes lifted to heaven for mercy are eyes lifted to the exalted Christ who intercedes (Rom 8:34).</p>',
    "2": '<p>A theme: the servant\'s eyes fixed on the master, waiting for direction. Christ modeled this perfect attentiveness toward the Father throughout his ministry — John 5:19 ("the Son can do nothing by himself; he can do only what he sees his Father doing"). He is both the pattern of dependence and the mediator through whom the mercy the servants seek is obtained (Heb 4:16 — "approach the throne of grace with confidence").</p>',
    "3": '<p>A shadow: "Have mercy upon us, for we have had more than enough of contempt." Christ bore the contempt of the world so that God\'s mercy could flow to those who cry for it. Heb 12:2 — he "endured the cross, despising the shame." He is the propitiation that makes this plea answerable (1 John 2:2); the mercy we ask for is the mercy he purchased.</p>',
    "4": '<p>A type: the scorn of the proud and the ease of the contemptuous directed at the lowly. This is the reception Christ received at the cross — Matt 27:39-44 (those who passed by derided him; the chief priests mocked him; the robbers reviled him). The righteous sufferer scorned by the proud is the type of which Christ\'s passion is the antitype. He bore our shame (Heb 12:2) so we could receive honor in him.</p>',
  },
  "124": {
    "1": '<p>A theme: the conditional "if it had not been the LORD who was on our side" is the premise of the entire gospel. Rom 8:31 — "If God is for us, who can be against us?" The rhetorical question that Paul raises is the confident answer to the psalm\'s conditional — in Christ, the "if" has been resolved: God is for us, definitively and irreversibly, having given his own Son (Rom 8:32).</p>',
    "2": '<p>A theme: YHWH on Israel\'s side when enemies rose against them — the pattern of divine solidarity that reaches its ultimate expression in the incarnation. God became flesh and stood with his people not just militarily but in death itself (Phil 2:8 — "he humbled himself by becoming obedient to the point of death, even death on a cross").</p>',
    "3": '<p>A type: the mortal threat of being swallowed alive. Christ descended into the depths of death — Eph 4:9 ("he also descended into the lower, earthly regions") — and was "swallowed" by the grave. The threat Israel faced became the reality Christ entered, precisely so that the threat would be defeated. Acts 2:24 — "it was not possible for him to be held by death."</p>',
    "4": '<p>A type: the flood sweeping over, the torrent passing over. Christ was baptized into death itself (Mark 10:38-39 — his "baptism" he would undergo). The waters of judgment that threatened to overwhelm Israel were the waters that Christ descended into — fulfilling the pattern of Noah and Jonah (Matt 12:40) — and the waters through which he brought his people safely to the other side (1 Pet 3:20-21).</p>',
    "5": '<p>A type: the raging waters. The Exodus pattern — escape through the sea — is the pattern Christ recapitulates. 1 Cor 10:1-2 — Israel was "baptized into Moses" in the cloud and sea; Christ is the greater Moses whose people are baptized into him (Rom 6:3-4), passing through death into resurrection life.</p>',
    "6": '<p>A shadow: "Blessed be the LORD, who has not given us as prey to their teeth!" Christ is the champion who defeats the devourer. 1 Pet 5:8 — Satan "prowls around like a roaring lion, seeking someone to devour." Heb 2:14-15 — Christ through death "destroyed the one who has the power of death, that is, the devil, and delivered all those who through fear of death were subject to lifelong slavery." The prey is not given over because Christ stood in the gap.</p>',
    "7": '<p>A theme: <strong>"we have escaped like a bird from the snare of the fowler; the snare is broken."</strong> Luke 4:18 — Christ came to "proclaim liberty to the captives." Gal 5:1 — "For freedom Christ has set us free." The snare of sin and the law\'s condemnation is broken at the cross (Col 2:14-15 — "having nailed it to the cross"). The bird that escapes is the believer freed in Christ.</p>',
    "8": '<p>A direct: <strong>"Our help is in the name of the LORD, who made heaven and earth."</strong> Acts 4:12 — "there is salvation in no one else, for there is no other name under heaven given among men by which we must be saved." The "name of the LORD" that is the help of his people is now known as the name of Jesus, the Lord and creator. Peter quotes this principle immediately after healing in Jesus\'s name (Acts 3:6,16).</p>',
  },
  "125": {
    "1": '<p>A shadow: "Those who trust in the LORD are like Mount Zion, which cannot be moved, but abides forever." Matt 7:24-25 — the one who builds on Christ\'s words stands like a house on rock when the floods come. 1 Cor 3:11 — "no one can lay a foundation other than that which is laid, which is Jesus Christ." The immovability comes from the foundation, not the builder.</p>',
    "2": '<p>A shadow: <strong>"As the mountains surround Jerusalem, so the LORD surrounds his people."</strong> John 10:28-29 — "I give them eternal life, and they shall never perish, and no one will snatch them out of my hand. My Father, who has given them to me, is greater than all, and no one is able to snatch them out of the Father\'s hand." Surrounded by Christ on one side and the Father on the other — a double enclosure that cannot be broken.</p>',
    "3": '<p>A shadow: "the scepter of wickedness shall not rest on the land allotted to the righteous." 1 John 3:8 — "The reason the Son of God appeared was to destroy the works of the devil." The scepter of wickedness that would rest on God\'s people is the power Christ came to overthrow — Col 2:15 ("having disarmed the rulers and authorities, he made a public spectacle of them, triumphing over them by the cross").</p>',
    "4": '<p>A revelation of God: "Do good, O LORD, to those who are good and to those who are upright in their hearts." The justice of God in rewarding the righteous finds its ultimate expression in Christ\'s imputed righteousness — the "good" ones are those clothed in Christ\'s righteousness (2 Cor 5:21). Christ the judge will say to his sheep, "Come, you who are blessed by my Father" (Matt 25:34).</p>',
    "5": '<p>A revelation of God: "those who turn aside to their crooked ways the LORD will lead away with evildoers." Matt 25:41 — "Depart from me, you cursed, into the eternal fire." Christ executes the final separation that the psalm anticipates. The psalm\'s "Peace be upon Israel!" is the peace that Christ pronounces over those who are his own (John 20:19-21; Eph 2:17).</p>',
  },
  "126": {
    "1": '<p>A type: <strong>"When the LORD restored the fortunes of Zion, we were like those who dream."</strong> The restoration that surpasses imagination — the disciples\' reaction to the resurrection was exactly this: Luke 24:41 — "they still disbelieved for joy and were marveling." The definitive restoration is Christ\'s resurrection, the firstfruits of the full restoration of God\'s people (1 Cor 15:20-23).</p>',
    "2": '<p>A type: "our mouth was filled with laughter, and our tongue with shouts of joy." The joy of the nations at Israel\'s restoration anticipates the eschatological joy of all peoples at the gospel — Acts 11:18 (Gentiles "glorified God, saying, \'Then to the Gentiles also God has granted repentance that leads to life\'"); Luke 15:10 ("there is joy before the angels of God over one sinner who repents").</p>',
    "3": '<p>A revelation of God: "The LORD has done great things for us; we are glad." The greatest act of God is the resurrection of Christ from the dead (Eph 1:19-20 — "the immeasurable greatness of his power toward us who believe, which he worked in Christ when he raised him from the dead"). All God\'s "great things" find their culmination in the Christ-event.</p>',
    "4": '<p>A shadow: "Restore our fortunes, O LORD, like streams in the Negeb!" The sudden, abundant streams in the dry desert prefigure the outpouring of the Spirit — John 7:37-38 ("rivers of living water" from those who believe in Christ). The eschatological ingathering: John 11:52 — Christ died "to gather into one the children of God who are scattered abroad"; Matt 8:11 — many will come from east and west to the kingdom.</p>',
    "5": '<p>A type: <strong>"Those who sow in tears shall reap with shouts of joy."</strong> John 12:24 — "unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit." The suffering-to-glory pattern — exile-return, sowing-reaping — is the pattern Christ enacts in his death and resurrection. His tears (John 11:35; Luke 19:41) become the resurrection joy (John 20:20).</p>',
    "6": '<p>A type: "He who goes out weeping, bearing the seed for sowing, shall come home with shouts of joy, bringing his sheaves with him." The portrait of the sower who weeps and returns with harvest is the portrait of Christ who "went out" to the cross bearing the seed of his own death, and who "came home" in the resurrection with the harvest of redeemed humanity. Heb 12:2 — "who for the joy that was set before him endured the cross."</p>',
  },
  "127": {
    "1": '<p>A shadow: <strong>"Unless the LORD builds the house, those who build it labor in vain."</strong> Matt 16:18 — "I will build my church, and the gates of hell shall not prevail against it." 1 Cor 3:10-11 — "I laid a foundation, and someone else is building upon it. Let each one take care how he builds upon it. For no one can lay a foundation other than that which is laid, which is Jesus Christ." All human effort to build what God must build is vanity; Christ is both the foundation and the builder.</p>',
    "2": '<p>A theme: <strong>"he gives sleep to his beloved."</strong> Matt 11:28-30 — "Come to me, all who labor and are heavy laden, and I will give you rest." The anxious toil of self-sufficiency (rising early, staying up late) stands against the rest of those who trust the builder. Christ himself demonstrated this rest — sleeping undisturbed in the storm (Mark 4:38), the one who gives rest embodying it perfectly.</p>',
    "3": '<p>A theme: "children are a heritage from the LORD, the fruit of the womb a reward." Those born through Christ are his heritage and offspring. John 1:12-13 — those who receive Christ are born "not of blood nor of the will of the flesh nor of the will of man, but of God." Isa 53:10 — "he shall see his offspring and prolong his days." The spiritual children born through Christ\'s work are his reward and inheritance.</p>',
    "4": '<p>A theme: "Like arrows in the hand of a warrior are the children of one\'s youth." The expansion of Christ\'s family through the proclamation of the gospel — disciples sent as arrows into all nations (Matt 28:19-20; John 12:32 — "I, when I am lifted up from the earth, will draw all people to myself"). The quiver-filling is the gathering of the elect from every nation (Rev 7:9).</p>',
    "5": '<p>A theme: "Blessed is the man who fills his quiver with them! He shall not be put to shame when he speaks with his enemies in the gate." Christ speaks before all his enemies with final authority — Phil 2:10-11 (every knee bows at his name). The one who builds the house, provides for the household, and fills his quiver is the victor who faces no shame. Heb 2:9 — Christ is "crowned with glory and honor because of the suffering of death."</p>',
  },
  "128": {
    "1": '<p>A revelation of God: <strong>"Blessed is everyone who fears the LORD, who walks in his ways."</strong> Prov 1:7 — the fear of the LORD is the beginning of wisdom. Christ is the wisdom of God incarnate (1 Cor 1:30 — "Christ Jesus, who became to us wisdom from God"). He perfectly "walks in God\'s ways" (John 8:29 — "I always do the things that are pleasing to him") and shares the blessedness of the God-fearer with all who are in him.</p>',
    "2": '<p>A theme: "You shall eat the fruit of the labor of your hands; you shall be blessed, and it shall be well with you." The fruitfulness belongs to those who abide in Christ. John 15:5 — "Whoever abides in me and I in him, he it is that bears much fruit, for apart from me you can do nothing." The laborer who eats the fruit of fruitful work is the believer whose labor in Christ is never in vain (1 Cor 15:58).</p>',
    "3": '<p>A theme: "Your wife will be like a fruitful vine within your house; your children will be like olive shoots around your table." The covenantal household bears fruit through Christ. Rev 21:2,9 — the church is the bride of Christ; the household of God (Eph 2:19) gathers around the table of the Lord (1 Cor 11:23-26). The fruitfulness of the vine is realized in Christ the true vine (John 15:1-8).</p>',
    "4": '<p>A revelation of God: the principle restated — "thus shall the man be blessed who fears the LORD." The blessing flows from right relationship with God, which is now mediated through Christ. Acts 3:25-26 — God raised up his servant and "sent him to you first, to bless you by turning every one of you from your wickedness." The ancient blessing given to Abraham comes to all peoples through Christ.</p>',
    "5": '<p>A shadow: "The LORD bless you from Zion! May you see the prosperity of Jerusalem all the days of your life!" The blessing that flows from Zion flows from the heavenly Jerusalem. Heb 12:22-24 — "you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem... to Jesus, the mediator of a new covenant." The prosperity of Jerusalem is the shalom of God\'s eternal city, centered on Christ.</p>',
    "6": '<p>A theme: "May you see your children\'s children! Peace be upon Israel!" The multigenerational vision is the vision of the church that Christ builds across all ages and nations. Matt 16:18 — "I will build my church, and the gates of hell shall not prevail against it." The "peace upon Israel" is the peace Christ himself is (Eph 2:14), declared over a community that includes every nation (Gal 3:29).</p>',
  },
  "129": {
    "1": '<p>A type: "Greatly have they afflicted me from my youth." The afflicted righteous one who suffers throughout life but is not ultimately overcome. Christ was opposed from birth (Matt 2:13-16, Herod\'s slaughter) through his entire ministry to the cross. Yet the affliction did not defeat him — Acts 2:24 ("it was not possible for him to be held by death"). John 16:33 — "I have overcome the world."</p>',
    "2": '<p>A type: "Greatly have they afflicted me from my youth, yet they have not prevailed against me." The repeated emphasis — afflicted, yet not defeated — is the pattern of Christ\'s suffering and vindication. The "yet" is the resurrection. All that the powers of darkness did to him did not prevail (Col 2:15 — "he made a public spectacle of them, triumphing over them by the cross").</p>',
    "3": '<p>A type: <strong>"The plowers plowed upon my back; they made long their furrows."</strong> The scourging of Christ. John 19:1 — Pilate had Jesus flogged. Isa 50:6 — "I gave my back to those who strike." Isa 53:5 — "by his wounds we are healed." The "long furrows" on the back of the sufferer are the stripes of the passion through which Christ bore our griefs and carried our sorrows.</p>',
    "4": '<p>A shadow: "The LORD is righteous; he has cut the cords of the wicked." Christ\'s death cuts the cords that bound humanity to condemnation and slavery. Col 2:14-15 — "having canceled the charge of our legal indebtedness, which stood against us and condemned us; he has taken it away, nailing it to the cross." The cords of the wicked are the debt of sin, cut at Calvary.</p>',
    "5": '<p>A revelation of God: "May all who hate Zion be put to shame and turned backward!" God\'s enemies will be made "a footstool for your feet" — Ps 110:1 (quoted in Heb 1:13). 1 Cor 15:25 — "he must reign until he has put all his enemies under his feet." The enemies of Zion who have been put to shame is the accomplished work of the cross and the completing work of Christ\'s reign.</p>',
    "6": '<p>A revelation of God: the wicked are "like the grass on the housetops, which withers before it grows up." Christ uses similar imagery of the fruitless and the fruitful — John 15:6 ("If anyone does not abide in me he is thrown away like a branch and withers"); Matt 13:5-6 (the seed without root springs up but withers). Those who oppose the Lord are like unrooted grass — impressive for a moment, gone entirely.</p>',
    "7": '<p>A revelation of God: the grass that "does not fill the hand of the reaper or the arms of him who binds sheaves." The harvest imagery contrasts the fruitless wicked with the fruitful righteous — the full harvest that Christ brings in (Matt 13:30,39-43: the final harvest; John 4:35 — "the fields are white for harvest"). What the wicked cannot produce, Christ produces abundantly.</p>',
    "8": '<p>A revelation of God: "The blessing of the LORD not be on them!" — those who pass by do not say "the blessing of the LORD be upon you." The final state of those who reject God is exclusion from his blessing. The inverse is the great blessing Christ pronounces over his own (Matt 5:3-12 — the Beatitudes). The psalm\'s negative and positive are both realized in the pronouncements of Christ the judge (Matt 25:34,41).</p>',
  },
  "130": {
    "1": '<p>A type: <strong>"Out of the depths I cry to you, O LORD!"</strong> The cry from the <em>maʿamāqqîm</em> (depths, deep waters) is the cry of Israel in extremity — and the cry of Christ from the cross. Matt 27:46 = Ps 22:1 — "My God, my God, why have you forsaken me?" Christ entered the deepest depths — Eph 4:9 ("he also descended into the lower, earthly regions") — so that no depth of human suffering falls outside his solidarity and redemptive reach.</p>',
    "2": '<p>A type: "O Lord, hear my voice! Let your ears be attentive to the cry of my pleas for mercy!" The intercessory cry that Scripture records as answered — God heard. This is the pattern of Christ\'s own prayer in Gethsemane and at the cross: Heb 5:7 — "he offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death, and he was heard because of his reverence." The Father heard and raised him.</p>',
    "3": '<p>A direct: <strong>"If you, O LORD, should mark iniquities, O Lord, who could stand?"</strong> The rhetorical answer is "no one" — Rom 3:23, "all have sinned and fall short of the glory of God." The gospel\'s answer is the imputed righteousness of Christ — 2 Cor 5:21 ("For our sake he made him to be sin who knew no sin, so that in him we might become the righteousness of God"). We "stand" only because Christ stood condemned in our place.</p>',
    "4": '<p>A direct: <strong>"But with you there is forgiveness, that you may be feared."</strong> Forgiveness is Christ\'s gift alone. Acts 13:38 — "through this man forgiveness of sins is proclaimed to you." Col 1:14 — "in whom we have redemption, the forgiveness of sins." The forgiveness that produces reverence (not presumption) is the forgiveness purchased at the cross — costly enough to be truly feared, free enough to be truly received.</p>',
    "5": '<p>A shadow: "I wait for the LORD, my soul waits, and in his word I hope." The intense waiting is Israel\'s messianic posture and now the church\'s eschatological posture. 1 Thess 1:9-10 — the Thessalonians "turned to God... and to wait for his Son from heaven." Rev 22:20 — "Come, Lord Jesus!" The "word" in which the hope resides is ultimately the Word made flesh (John 1:14) and the word of promise that he will return.</p>',
    "6": '<p>A shadow: "my soul waits for the Lord more than watchmen wait for the morning." The watchman straining for dawn is the image of eschatological yearning. Rom 8:23 — "we ourselves, who have the firstfruits of the Spirit, groan inwardly as we wait eagerly for adoption as sons, the redemption of our bodies." The morning that ends the watch is the appearing of Christ (2 Pet 1:19 — "the morning star rises in your hearts").</p>',
    "7": '<p>A shadow: "For with the LORD there is steadfast love, and with him is plentiful redemption." Plentiful redemption — <em>harbēh-ʿimmô p̄edût</em> — is the sufficiency and overflow of the atonement. 1 Tim 2:6 — Christ "gave himself as a ransom for all." Eph 1:7 — "In him we have redemption through his blood, the forgiveness of sins, in accordance with the riches of God\'s grace that he lavished on us." The plentiful redemption is the cross.</p>',
    "8": '<p>A direct: <strong>"And he will redeem Israel from all his iniquities."</strong> Matt 1:21 — "you shall call his name Jesus, for he will save his people from their sins." The angel\'s announcement is the direct fulfillment of this verse. Titus 2:14 — Christ "gave himself for us to redeem us from all lawlessness." The God who promises in Ps 130:8 to redeem Israel from all iniquity sends his Son in Matt 1:21 to accomplish it. The verse and its fulfillment are inseparable.</p>',
  },
  "131": {
    "1": '<p>A type: "My heart is not lifted up; my eyes are not raised too high." David\'s declaration of humility is the posture Christ embodied perfectly. Phil 2:5-8 — Christ "did not count equality with God a thing to be grasped, but emptied himself, taking the form of a servant." Matt 11:29 — "I am gentle and lowly in heart." The Son of God, who had every reason to lift his heart high, descended in humility — the type becomes the antitype without remainder.</p>',
    "2": '<p>A theme: <strong>"like a weaned child with its mother; like a weaned child is my soul within me."</strong> The weaned child (content in the mother\'s presence, no longer crying for milk) models the trust Christ calls his disciples to: Matt 18:3 — "unless you turn and become like little children, you will never enter the kingdom of heaven." Matt 11:28-30 — his yoke is easy; in him the soul finds rest without striving. The quiet soul is the soul resting in Christ.</p>',
    "3": '<p>A shadow: "O Israel, hope in the LORD from this time forth and forevermore." The eternal hope is "Christ in you, the hope of glory" (Col 1:27). Acts 28:20 — Paul was bound in chains because of "the hope of Israel" — which is Christ himself. 1 Pet 1:3 — "a living hope through the resurrection of Jesus Christ from the dead." The hope that spans "from this time forth and forevermore" is anchored in the resurrection and consummated at Christ\'s return.</p>',
  },
  "132": {
    "1": '<p>A type: "Remember, O LORD, in David\'s favor, all the hardships he endured." David\'s hardships in seeking a dwelling for God are a type of Christ\'s mission to establish the true temple. John 2:19-21 — "destroy this temple, and in three days I will raise it up" (spoken of his body). David sought a house for God\'s ark; in Christ, God himself becomes the dwelling among his people permanently (Rev 21:3,22).</p>',
    "2": '<p>A type: "how he swore to the LORD and vowed to the Mighty One of Jacob." David\'s sworn oath to find a place for the LORD reflects the covenant commitment that Christ fulfills. Heb 6:17-18 — "God desired to show more convincingly to the heirs of the promise the unchangeable character of his purpose... so that we who have fled for refuge might have strong encouragement to hold fast to the hope set before us." God\'s own oath is the guarantee of the messianic promise.</p>',
    "3": '<p>A type: "I will not enter my house or get into my bed, I will not give sleep to my eyes or slumber to my eyelids." David\'s restless urgency for God\'s dwelling is a type of Christ\'s zeal. John 2:17 — "Zeal for your house will consume me" (applied to Christ at the temple cleansing). The urgency David felt about establishing a place for God\'s presence is the urgency Christ embodied in establishing the new meeting place between God and humanity.</p>',
    "4": '<p>A type: "until I find a place for the LORD, a dwelling place for the Mighty One of Jacob." The place David sought is not the stone temple but the temple Christ is. Heb 9:11-12 — Christ entered "the greater and more perfect tabernacle, not made with hands, that is, not of this creation." The ark found its resting place; the glory of God found its dwelling place in the incarnate Son (John 1:14 — "the Word... dwelt among us").</p>',
    "5": '<p>A type: "a dwelling place for the Mighty One of Jacob." The Mighty One who is Jacob\'s God — the God of covenant — finds his ultimate dwelling in Christ and in the community gathered around him. 1 Cor 3:16 — "you are God\'s temple and God\'s Spirit dwells in you." Eph 2:21-22 — the whole structure grows into "a holy temple in the Lord... a dwelling place for God by the Spirit."</p>',
    "6": '<p>A type: "We heard of it in Ephrathah; we found it in the fields of Jaar." The ark\'s journey from obscurity to the city of David prefigures the hidden preparation of God\'s purposes in Christ — born obscurely in Bethlehem (= Ephrathah, Mic 5:2; Matt 2:6), kept hidden until his time (Luke 2:52). The ark found and brought to Jerusalem is the type of the glory of God recognized and enthroned in Christ.</p>',
    "7": '<p>A type: "Let us go to his dwelling place; let us worship at his footstool!" The pilgrimage call echoes through the Psalter. Heb 12:22 — believers have "come to Mount Zion and to the city of the living God, the heavenly Jerusalem." The footstool at which worship is offered is now the throne of the ascended Christ — Rev 4-5 (the worship of heaven centered on the Lamb).</p>',
    "8": '<p>A type: "Arise, O LORD, and go to your resting place, you and the ark of your might." The ark of God\'s might points to Christ, who is "the power of God and the wisdom of God" (1 Cor 1:24). The "resting place" for God is fulfilled in Christ\'s resurrection and session at the right hand of the Father — Heb 1:3 ("sat down at the right hand of the Majesty on high").</p>',
    "9": '<p>A type: "Let your priests be clothed with righteousness, and let your saints shout for joy." The priests clothed in righteousness are the believers clothed in Christ\'s righteousness (2 Cor 5:21; Rev 19:8 — "the righteous deeds of the saints"). Rev 7:9 — the great multitude before the throne clothed in white robes shouting for joy. The priestly garment of righteousness is the robe Christ provides.</p>',
    "10": '<p>A shadow: "For the sake of your servant David, do not turn away the face of your anointed one." The <em>māšîaḥ</em> — the anointed one — whose face must not be turned away. Christ now intercedes from the Father\'s right hand: Heb 7:25 — "he always lives to make intercession for them." The prayer that God not reject the anointed is answered permanently in Christ\'s accepted intercession before the Father (Heb 9:24 — "now to appear in the presence of God for us").</p>',
    "11": '<p>A direct: <strong>"The LORD swore to David a sure oath from which he will not turn back: \'One of the sons of your body I will set on your throne.\'"</strong> Acts 2:30 — "David was a prophet, and knowing that God had sworn with an oath to him that he would set one of his descendants on his throne, he spoke about the resurrection of the Christ." Peter directly applies this verse to Christ\'s resurrection. One of the most explicitly messianic verses in the entire Psalter.</p>',
    "12": '<p>A shadow: "If your sons keep my covenant and my testimonies that I shall teach them, their sons also forever shall sit on your throne." The conditional "if" of David\'s natural sons is resolved by Christ, the one son who kept the covenant perfectly (Heb 4:15 — "without sin"). The eternal throne depends on perfect obedience — only Christ provided it. Heb 1:8 — "Your throne, O God, is forever and ever, the scepter of uprightness is the scepter of your kingdom."</p>',
    "13": '<p>A shadow: "For the LORD has chosen Zion; he has desired it for his dwelling place." The final resting place of God is not the stone temple but the heavenly Jerusalem where God and Christ dwell with their people forever. Rev 21:3,22 — "Behold, the dwelling place of God is with man... its temple is the Lord God the Almighty and the Lamb." Heb 12:22 — the city that believers have come to is the dwelling place God has chosen.</p>',
    "14": '<p>A shadow: "This is my resting place forever; here I will dwell, for I have desired it." The permanent, final dwelling of God realized in Christ and the new creation. Rev 21:3 — "He will dwell with them, and they will be his people, and God himself will be with them as their God." What the ark in Jerusalem temporarily signified, the presence of Christ permanently establishes.</p>',
    "15": '<p>A type: "I will abundantly bless her provisions; I will satisfy her poor with bread." Christ satisfies the hungry with bread. John 6:35 — "I am the bread of life; whoever comes to me shall not hunger." The feeding of the five thousand (John 6:1-15) and four thousand (Matt 15:32-39) demonstrate the abundance of Zion\'s messianic provisions. Luke 1:53 — "he has filled the hungry with good things."</p>',
    "16": '<p>A type: "Her priests I will clothe with salvation, and her saints will shout for joy." Salvation as clothing — Isa 61:10 ("he has clothed me with the garments of salvation"), applied to Christ in Luke 4:18 ("he has sent me to proclaim liberty to the captives"). Rev 7:9 — the great multitude clothed in white robes shouting before the throne. The priestly garment is the salvation Christ provides, worn by all who are his.</p>',
    "17": '<p>A direct: <strong>"There I will make a horn grow for David; I have prepared a lamp for my anointed."</strong> Luke 1:69 — "he has raised up a horn of salvation for us in the house of his servant David." Luke 1:78-79 — "the sunrise from on high will visit us, to give light to those who sit in darkness." This verse is directly quoted and applied to Christ in Zechariah\'s Benedictus. The horn of strength and the lamp of lineage and light — both fulfilled in Jesus of Nazareth, son of David.</p>',
    "18": '<p>A shadow: "His enemies I will clothe with shame, but on him his crown will gleam." The victorious, crowned king after his enemies are defeated. Heb 2:9 — "we see him who for a little while was made lower than the angels, namely Jesus, crowned with glory and honor because of the suffering of death." Phil 2:9-11 — "God has highly exalted him and bestowed on him the name that is above every name." The crown that gleams is the crown of the exalted Christ after the cross.</p>',
  },
  "133": {
    "1": '<p>A direct: <strong>"Behold, how good and pleasant it is when brothers dwell in unity!"</strong> John 17:21-23 — "that they may all be one, just as you, Father, are in me, and I in you, that they also may be in us." Christ prays for the unity the psalm describes — and he creates it through his death. Eph 2:14-16 — "he himself is our peace, who has made the two groups one and has destroyed the barrier, the dividing wall of hostility... creating in himself one new humanity." The psalm\'s vision is Christ\'s own intention.</p>',
    "2": '<p>A type: "It is like the precious oil on the head, running down on the beard, on the beard of Aaron, running down on the collar of his robes." The <strong>anointing oil</strong> flowing from Aaron\'s head is a type of the Spirit poured out from Christ at Pentecost. Acts 2:33 — "Being therefore exalted at the right hand of God, and having received from the Father the promise of the Holy Spirit, he has poured out this that you yourselves are seeing and hearing." Christ is the Anointed One (<em>Māšîaḥ</em> = <em>Christos</em>) from whom the anointing flows to all his people (1 John 2:20,27 — "you have been anointed by the Holy One").</p>',
    "3": '<p>A direct: <strong>"For there the LORD has commanded the blessing, life forevermore."</strong> John 17:3 — "And this is eternal life, that they know you, the only true God, and Jesus Christ whom you have sent." Rev 22:14 — "Blessed are those who wash their robes, so that they may have the right to the tree of life." The "life forevermore" commanded as a blessing at Zion is the eternal life that Christ gives to all who are united in him. The blessing, the unity, and the life all converge in Christ.</p>',
  },
}

def main():
    existing = load_comm('mkt-christ', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-christ', 'psalms', existing)
    # INTENT: Verify coverage for Psalms 120-133 against interlinear verse inventory
    # CHANGE? If interlinear/psalms.json verse counts change, recount expected totals here
    # VERIFY: Console shows wrote data/commentary/mkt-christ/psalms.json; no missing verses
    il = json.loads((ROOT / 'data' / 'interlinear' / 'psalms.json').read_text())
    out = json.loads((ROOT / 'data' / 'commentary' / 'mkt-christ' / 'psalms.json').read_text())
    missing = []
    for ch in range(120, 134):
        ck = str(ch)
        for v in il.get(ck, {}):
            if v not in out.get(ck, {}):
                missing.append(f'{ch}:{v}')
    if missing:
        print(f'  MISSING: {missing}')
    else:
        print(f'  OK: all Psalms 120-133 mkt-christ verses present ({sum(len(il.get(str(c),{})) for c in range(120,134))} verses)')

if __name__ == '__main__':
    main()
